package com.google.gson.stream;
import static com.google.gson.stream.JsonScope.DANGLING_NAME;
import static com.google.gson.stream.JsonScope.EMPTY_ARRAY;
import static com.google.gson.stream.JsonScope.EMPTY_DOCUMENT;
import static com.google.gson.stream.JsonScope.EMPTY_OBJECT;
import static com.google.gson.stream.JsonScope.NONEMPTY_ARRAY;
import static com.google.gson.stream.JsonScope.NONEMPTY_DOCUMENT;
import static com.google.gson.stream.JsonScope.NONEMPTY_OBJECT;
import java.io.Closeable;
import java.io.Flushable;
import java.io.Writer;
import java.math.BigDecimal;
import java.math.BigInteger;
import java.util.Arrays;
import java.util.Objects;
import java.util.concurrent.atomic.AtomicInteger;
import java.util.concurrent.atomic.AtomicLong;
import java.util.regex.Pattern;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.stream.JsonWriter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.io.IOException;
import java.io.StringWriter;
import java.lang.reflect.Field;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

class JsonWriterTest {

  private JsonWriter jsonWriter;
  private StringWriter stringWriter;

  private Method writeDeferredNameMethod;

  @BeforeEach
  void setUp() throws NoSuchMethodException {
    stringWriter = new StringWriter();
    jsonWriter = new JsonWriter(stringWriter);

    // Access private method via reflection
    writeDeferredNameMethod = JsonWriter.class.getDeclaredMethod("writeDeferredName");
    writeDeferredNameMethod.setAccessible(true);
  }

  @Test
  void writeDeferredName_deferredNameNull_noAction() throws Throwable {
    // deferredName is null by default, so invoking should do nothing and not throw
    writeDeferredNameMethod.invoke(jsonWriter);
    // No exception means success, output should be empty
    assertEquals("", stringWriter.toString());
  }

  @Test
  void writeDeferredName_deferredNameSet_executesBeforeNameAndString() throws Throwable {
    // Use subclass to override private methods for spying
    JsonWriter spyWriter = new JsonWriterSpy(stringWriter);

    // Set deferredName field to a non-null value via reflection
    Field deferredNameField = JsonWriter.class.getDeclaredField("deferredName");
    deferredNameField.setAccessible(true);
    deferredNameField.set(spyWriter, "testName");

    // Invoke writeDeferredName on spy
    writeDeferredNameMethod.invoke(spyWriter);

    // Verify beforeName() called once
    assertEquals(1, ((JsonWriterSpy) spyWriter).beforeNameCallCount, "beforeName should be called once");

    // Verify string(String) called once with "testName"
    assertEquals(1, ((JsonWriterSpy) spyWriter).stringCallCount, "string should be called once");
    assertEquals("testName", ((JsonWriterSpy) spyWriter).stringArg, "string called with argument 'testName'");

    // Verify deferredName is set to null after invocation
    assertNull(deferredNameField.get(spyWriter));
  }

  @Test
  void writeDeferredName_beforeNameThrowsIOException_propagates() throws Throwable {
    JsonWriter spyWriter = new JsonWriterSpy(stringWriter) {
      @Override
      void beforeName() throws IOException {
        throw new IOException("beforeName failure");
      }
    };

    Field deferredNameField = JsonWriter.class.getDeclaredField("deferredName");
    deferredNameField.setAccessible(true);
    deferredNameField.set(spyWriter, "testName");

    InvocationTargetException thrown = assertThrows(InvocationTargetException.class, () -> {
      writeDeferredNameMethod.invoke(spyWriter);
    });
    assertTrue(thrown.getCause() instanceof IOException);
    assertEquals("beforeName failure", thrown.getCause().getMessage());

    // deferredName should remain unchanged because exception occurs before null assignment
    assertEquals("testName", deferredNameField.get(spyWriter));
  }

  @Test
  void writeDeferredName_stringThrowsIOException_propagates() throws Throwable {
    JsonWriter spyWriter = new JsonWriterSpy(stringWriter) {
      @Override
      void string(String value) throws IOException {
        throw new IOException("string failure");
      }
    };

    Field deferredNameField = JsonWriter.class.getDeclaredField("deferredName");
    deferredNameField.setAccessible(true);
    deferredNameField.set(spyWriter, "testName");

    InvocationTargetException thrown = assertThrows(InvocationTargetException.class, () -> {
      writeDeferredNameMethod.invoke(spyWriter);
    });
    assertTrue(thrown.getCause() instanceof IOException);
    assertEquals("string failure", thrown.getCause().getMessage());

    // deferredName should remain unchanged because exception occurs before null assignment
    assertEquals("testName", deferredNameField.get(spyWriter));
  }

  // Subclass to expose private methods for spying and overriding
  private static class JsonWriterSpy extends JsonWriter {
    int beforeNameCallCount = 0;
    int stringCallCount = 0;
    String stringArg = null;

    JsonWriterSpy(StringWriter out) {
      super(out);
    }

    @Override
    void beforeName() throws IOException {
      beforeNameCallCount++;
      super.beforeName();
    }

    @Override
    void string(String value) throws IOException {
      stringCallCount++;
      stringArg = value;
      super.string(value);
    }
  }
}

